INSERT INTO `tblpages` (`id`, `type`, `detail`) VALUES (1,'terms','																														<p align=\"justify\"><font size=\"2\"><strong><font color=\"#990000\">(1) ACCEPTANCE OF TERMS</font><br><br></strong>Welcome to Yahoo! India. 1Yahoo Web Services India Private Limited Yahoo\", \"we\" or \"us\" as the case may be) provides the Service (defined below) to you, subject to the following Terms of Service (\"TOS\"), which may be updated by us from time to time without notice to you. You can review the most current version of the TOS at any time at: <a href=\"http://in.docs.yahoo.com/info/terms/\">http://in.docs.yahoo.com/info/terms/</a>. In addition, when using particular Yahoo services or third party services, you and Yahoo shall be subject to any posted guidelines or rules applicable to such services which may be posted from time to time. All such guidelines or rules, which maybe subject to change, are hereby incorporated by reference into the TOS. In most cases the guides and rules are specific to a particular part of the Service and will assist you in applying the TOS to that part, but to the extent of any inconsistency between the TOS and any guide or rule, the TOS will prevail. We may also offer other services from time to time that are governed by different Terms of Services, in which case the TOS do not apply to such other services if and to the extent expressly excluded by such different Terms of Services. Yahoo also may offer other services from time to time that are governed by different Terms of Services. These TOS do not apply to such other services that are governed by different Terms of Service. </font></p>\r\n<p align=\"justify\"><font size=\"2\">Welcome to Yahoo! India. Yahoo Web Services India Private Limited Yahoo\", \"we\" or \"us\" as the case may be) provides the Service (defined below) to you, subject to the following Terms of Service (\"TOS\"), which may be updated by us from time to time without notice to you. You can review the most current version of the TOS at any time at: </font><a href=\"http://in.docs.yahoo.com/info/terms/\"><font size=\"2\">http://in.docs.yahoo.com/info/terms/</font></a><font size=\"2\">. In addition, when using particular Yahoo services or third party services, you and Yahoo shall be subject to any posted guidelines or rules applicable to such services which may be posted from time to time. All such guidelines or rules, which maybe subject to change, are hereby incorporated by reference into the TOS. In most cases the guides and rules are specific to a particular part of the Service and will assist you in applying the TOS to that part, but to the extent of any inconsistency between the TOS and any guide or rule, the TOS will prevail. We may also offer other services from time to time that are governed by different Terms of Services, in which case the TOS do not apply to such other services if and to the extent expressly excluded by such different Terms of Services. Yahoo also may offer other services from time to time that are governed by different Terms of Services. These TOS do not apply to such other services that are governed by different Terms of Service. </font></p>\r\n<p align=\"justify\"><font size=\"2\">Welcome to Yahoo! India. Yahoo Web Services India Private Limited Yahoo\", \"we\" or \"us\" as the case may be) provides the Service (defined below) to you, subject to the following Terms of Service (\"TOS\"), which may be updated by us from time to time without notice to you. You can review the most current version of the TOS at any time at: </font><a href=\"http://in.docs.yahoo.com/info/terms/\"><font size=\"2\">http://in.docs.yahoo.com/info/terms/</font></a><font size=\"2\">. In addition, when using particular Yahoo services or third party services, you and Yahoo shall be subject to any posted guidelines or rules applicable to such services which may be posted from time to time. All such guidelines or rules, which maybe subject to change, are hereby incorporated by reference into the TOS. In most cases the guides and rules are specific to a particular part of the Service and will assist you in applying the TOS to that part, but to the extent of any inconsistency between the TOS and any guide or rule, the TOS will prevail. We may also offer other services from time to time that are governed by different Terms of Services, in which case the TOS do not apply to such other services if and to the extent expressly excluded by such different Terms of Services. Yahoo also may offer other services from time to time that are governed by different Terms of Services. These TOS do not apply to such other services that are governed by different Terms of Service. </font></p>\r\n										\r\n										\r\n										'),(2,'privacy','																				<span style=\"color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 14px; text-align: justify;\">At vero eos et accusamus et iusto odio dignissimos ducimus qui blanditiis praesentium voluptatum deleniti atque corrupti quos dolores et quas molestias excepturi sint occaecati cupiditate non provident, similique sunt in culpa qui officia deserunt mollitia animi, id est laborum et dolorum fuga. Et harum quidem rerum facilis est et expedita distinctio. Nam libero tempore, cum soluta nobis est eligendi optio cumque nihil impedit quo minus id quod maxime placeat facere possimus, omnis voluptas assumenda est, omnis dolor repellendus. Temporibus autem quibusdam et aut officiis debitis aut rerum necessitatibus saepe eveniet ut et voluptates repudiandae sint et molestiae non recusandae. Itaque earum rerum hic tenetur a sapiente delectus, ut aut reiciendis voluptatibus maiores alias consequatur aut perferendis doloribus asperiores repellat.</span><div><div style=\"text-align: justify;\"><span style=\"color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 14px;\"><br></span></div><div style=\"text-align: justify;\"><span style=\"color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 14px;\"><span style=\"font-weight: bold;\">Data Security:</span> We employ security measures to protect your personal information from unauthorized access, alteration, disclosure, or destruction. However, no data transmission over the internet can be guaranteed as completely secure.</span><br></div><div><span style=\"color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 14px; text-align: justify;\"><br></span></div><div style=\"text-align: justify;\"><span style=\"color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 14px;\"><span style=\"font-weight: bold;\">Your Choices:</span>&nbsp;You have the right to access, update, and correct your personal information. You may also opt-out of receiving marketing communications from us at any time.</span><br></div></div><div style=\"text-align: justify;\"><span style=\"color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 14px;\"><br></span></div><div style=\"text-align: justify;\"><span style=\"color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 14px;\"><span style=\"font-weight: bold;\">Cookies and Tracking Technologies:</span> We use cookies and similar technologies to enhance your browsing experience and collect data about your usage of our platform. You can control cookies preferences through your browser settings. Changes to Privacy Policy We reserve the right to update this Privacy Policy from time to time. We will notify you of significant changes by posting a prominent notice on our website.&nbsp;</span></div><div style=\"text-align: justify;\"><span style=\"color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 14px;\"><br></span></div><div style=\"text-align: justify;\"><span style=\"color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 14px;\"><span style=\"font-weight: bold;\">Contact Us:</span> If you have any questions or concerns about our Privacy Policy, please contact us at [Contact Email or Phone Number]. Please note that this is a generic template and should be customized to reflect the specific practices and policies of your travel and tourism management system. You may want to consult with legal professionals to ensure that your privacy policy complies with relevant laws and regulations.</span><br></div>'),(3,'aboutus','																				<div><span style=\"color: rgb(0, 0, 0); font-family: Georgia; font-size: 15px; text-align: justify; font-weight: bold;\">Welcome to Tourism Management System!!!</span></div><span style=\"font-family: &quot;courier new&quot;;\"><span style=\"color: rgb(0, 0, 0); font-size: 15px; text-align: justify;\">Since then, our courteous and committed team members have always ensured a pleasant and enjoyable tour for the clients. This arduous effort has enabled Shreya Tour &amp; Travels to be recognized as a dependable Travel Solutions provider with three offices Delhi.</span><span style=\"color: rgb(80, 80, 80); font-size: 13px;\">&nbsp;We have got packages to suit the discerning traveler\'s budget and savor. Book your dream vacation online. Supported quality and proposals of our travel consultants, we have a tendency to welcome you to decide on from holidays packages and customize them according to your plan.</span></span>\r\n										<div><span style=\"font-family: &quot;courier new&quot;;\"><span style=\"color: rgb(80, 80, 80); font-size: 13px;\"><br></span></span></div><div><p class=\"MsoNormal\"><b><span style=\"line-height: 107%; font-size: x-large;\">About Us<o:p></o:p></span></b></p>\r\n\r\n<p class=\"MsoNormal\"><span style=\"font-family: &quot;times new roman&quot;; font-size: large;\">At Travel and tourism management system, we are passionate\r\nabout creating unforgettable travel experiences that inspire, enrich, and\r\nconnect people to the world\'s most captivating destinations. With a deep\r\nappreciation for the transformative power of travel, we have curated a range of\r\nmeticulously designed travel packages and services to cater to the diverse\r\ninterests and preferences of our valued travelers.<o:p></o:p></span></p>\r\n\r\n<p class=\"MsoNormal\"><span style=\"font-family: &quot;times new roman&quot;; font-size: large;\">Founded on the belief that every journey is an opportunity\r\nfor discovery and growth, our mission is to offer seamless and personalized\r\ntravel solutions that cater to the wanderlust of adventure seekers, cultural\r\nenthusiasts, and leisure travelers alike. With years of expertise in the travel\r\nindustry, we have forged strong partnerships with top-tier hotels, airlines, and\r\nlocal guides to ensure that every aspect of your journey is infused with\r\nauthenticity and excellence.<o:p></o:p></span></p>\r\n\r\n<p class=\"MsoNormal\"><span style=\"font-family: &quot;times new roman&quot;; font-size: large;\">Our dedicated team of travel experts is committed to\r\nproviding you with exceptional customer service, helping you craft journeys\r\nthat reflect your unique style and desires. Whether you\'re seeking an immersive\r\ncultural experience, an adrenaline-pumping adventure, or a serene escape to\r\nnature\'s beauty, we have meticulously designed travel itineraries that\r\nencompass the essence of your dream getaway.<o:p></o:p></span></p>\r\n\r\n<p class=\"MsoNormal\"><span style=\"font-family: &quot;times new roman&quot;; font-size: large;\">Beyond crafting exceptional travel experiences, we are\r\ndevoted to fostering sustainable and responsible tourism practices. We believe\r\nin leaving a positive impact on the destinations we visit, supporting local\r\ncommunities, and preserving the natural beauty that makes each place special.<o:p></o:p></span></p>\r\n\r\n<p class=\"MsoNormal\"><span style=\"font-family: &quot;times new roman&quot;; font-size: large;\">Join us on a journey that goes beyond the ordinary and opens\r\nup a world of boundless exploration. With every destination, we strive to\r\ncreate memories that linger long after the journey is over. Welcome to [Your\r\nCompany Name], where your travel dreams come to life.<o:p></o:p></span></p>\r\n\r\n<div class=\"MsoNormal\" align=\"center\" style=\"text-align:center\">\r\n\r\n<hr size=\"0\" width=\"100%\" noshade=\"\" style=\"color:#D1D5DB\" align=\"center\">\r\n\r\n</div>\r\n\r\n<p class=\"MsoNormal\"><span style=\"font-size: large;\"><span style=\"font-family: &quot;times new roman&quot;;\">Feel free to customize this passage to align with your\r\ncompany\'s values, goals, and unique offerings</span>.</span><o:p></o:p></p></div>\r\n										'),(11,'contact','<p class=\"MsoNormal\">Contact Us<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\">Welcome to our Contact Us page! We\'re delighted that you\'re\r\ninterested in reaching out to us. Whether you have inquiries about our travel\r\nservices, need assistance with bookings, or just want to share your thoughts,\r\nwe\'re here to listen and help.<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p>\r\n\r\n<p class=\"MsoNormal\">Our dedicated team at [Your Company Name] is committed to\r\nproviding you with top-notch customer support. We value your feedback and are\r\neager to assist you in making your travel plans a reality.<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p>\r\n\r\n<p class=\"MsoNormal\">How to Get in Touch<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p>\r\n\r\n<p class=\"MsoNormal\">There are various ways you can contact us:<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p>\r\n\r\n<p class=\"MsoNormal\">1. Phone:<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\">Feel free to give us a call at [Your Contact Number]. Our\r\nfriendly customer support agents are available during our operating hours to\r\naddress your questions and provide guidance.<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p>\r\n\r\n<p class=\"MsoNormal\">2. Email:<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\">You can send us an email at [Your Contact Email]. Whether\r\nit\'s a question about a specific destination, a request for customized travel\r\npackages, or anything else, we\'re here to respond promptly.<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p>\r\n\r\n<p class=\"MsoNormal\">3. Visit Our Office:<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\">If you\'re in the area, we welcome you to stop by our office\r\nat [Your Company Address]. Our team will be delighted to meet you in person and\r\ndiscuss your travel preferences.<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p>\r\n\r\n<p class=\"MsoNormal\">4. Online Inquiry Form:<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\">For your convenience, we\'ve set up an online inquiry form\r\nright here on our website. Simply fill in your details and your message, and\r\nwe\'ll ensure that the right person gets back to you with the information you\r\nneed.<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p>\r\n\r\n<p class=\"MsoNormal\">5. Social Media:<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\">Stay connected with us on our social media platforms! Follow\r\nus on Facebook, Twitter, Instagram, and more [@YourSocialHandles]. We regularly\r\nshare travel tips, destination inspiration, and updates about our services.<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p>\r\n\r\n<p class=\"MsoNormal\">At [Your Company Name], we\'re more than just a travel and\r\ntourism management system â we\'re your partners in creating exceptional travel\r\nexperiences. Your satisfaction is our priority, and we\'re here to assist you\r\nevery step of the way. Contact us today and let\'s start planning your next\r\nadventure!<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p>\r\n\r\n<p class=\"MsoNormal\">---<o:p></o:p></p>\r\n\r\n<p class=\"MsoNormal\">Feel free to personalize and modify the content to match\r\nyour brand\'s voice and specific contact details. This passage-style content\r\naims to engage and reassure visitors that you\'re available to assist them with\r\ntheir travel needs.<o:p></o:p></p>');
