INSERT INTO `tbltourpackages` (`PackageId`, `PackageName`, `PackageType`, `PackageLocation`, `PackagePrice`, `PackageFetures`, `PackageDetails`, `PackageInfo`, `PackageImage`, `Creationdate`, `UpdationDate`) VALUES (1,'Goa Beach Resort','Couple','Goa',15000,'Wifi, Pool, Spa, Meals','<p style=\"margin-bottom: 1rem; font-family: &quot;Avenir Next&quot;, Helvetica, Arial, serif; line-height: 1.5rem; color: rgb(93, 105, 116); font-size: 14px; letter-spacing: 0.14px; text-align: justify;\">Experience the magic of Goa with our Goa Beach Resort package. Whether you are seeking relaxation or adventure, this tour offers the perfect itinerary tailored to your preferences. Immerse yourself in the local culture, explore stunning landscapes, and savor delicious culinary delights. From guided tours to free exploration days, every moment of this journey is designed to create unforgettable memories. This package includes all essential amenities so you can focus entirely on your vacation.</p><p style=\"margin-bottom: 1rem; font-family: &quot;Avenir Next&quot;, Helvetica, Arial, serif; line-height: 1.5rem; color: rgb(93, 105, 116); font-size: 14px; letter-spacing: 0.14px; text-align: justify;\"><span style=\"font-weight: 600;\">Available Activities:</span></p><ul style=\"margin-bottom: 1rem; color: rgb(93, 105, 116); font-family: &quot;Avenir Next&quot;, Helvetica, Arial, serif; font-size: 14px; letter-spacing: 0.14px;\"><li style=\"text-align: justify;\">Guided City/Nature Tours</li><li style=\"text-align: justify;\">Local Cultural Experiences and Shows</li><li style=\"text-align: justify;\">Shopping and Leisure Time</li><li style=\"text-align: justify;\">Photography Sessions</li><li style=\"text-align: justify;\">Outdoor Sports/Activities (depending on terrain)</li></ul><p style=\"margin-bottom: 1rem; font-family: &quot;Avenir Next&quot;, Helvetica, Arial, serif; line-height: 1.5rem; color: rgb(93, 105, 116); font-size: 14px; letter-spacing: 0.14px;\"><span style=\"font-weight: 600;\"><u>Food Menu</u></span></p><p style=\"margin-bottom: 1rem; font-family: &quot;Avenir Next&quot;, Helvetica, Arial, serif; line-height: 1.5rem; color: rgb(93, 105, 116); font-size: 14px; letter-spacing: 0.14px;\"><span style=\"font-weight: 600;\">Breakfast&nbsp;</span>8:00 AM to 9:30 AM<span style=\"font-weight: 600;\">:</span> Continental/Local Buffet, Coffee, Tea</p><p style=\"margin-bottom: 1rem; font-family: &quot;Avenir Next&quot;, Helvetica, Arial, serif; line-height: 1.5rem; color: rgb(93, 105, 116); font-size: 14px; letter-spacing: 0.14px;\"><span style=\"font-weight: 600;\">Lunch&nbsp;</span>1:00 PM to 2:30 PM: Authentic Regional Thali/Platter, Refreshing Drinks</p><p style=\"margin-bottom: 1rem; font-family: &quot;Avenir Next&quot;, Helvetica, Arial, serif; line-height: 1.5rem; color: rgb(93, 105, 116); font-size: 14px; letter-spacing: 0.14px;\"><span style=\"font-weight: 600;\">Dinner 8</span>:00 PM to 10:00 PM: Multi-cuisine Buffet, Dessert, Soup</p>','<span style=\"font-weight: bold;\">Remember!!</span><br><ul><li>Always be respectful of the rules and guidelines of the tourist spots.</li><li>Do not litter, use a disposable bag as a portable trash bin.</li><li>Unmarried couples must verify local hotel policies before booking.</li><li>You must show valid ID/Passport during check-in.</li><li>If you fail to show proper ID then you will not be allowed to check-in.</li><li>Consumption of any sort of illegal drugs is strictly prohibited.</li><li>Follow the timings strictly for guided tours and transport.</li></ul><p></p><span data-v-d27cb9aa=\"\" style=\"font-size: 14px; line-height: 22px; color: rgb(28, 60, 107); font-family: &quot;Avenir Next&quot;, Helvetica, Arial, serif; letter-spacing: 0.14px;\"><span data-v-d27cb9aa=\"\" style=\"font-weight: 600;\">Requirements:</span><p data-v-d27cb9aa=\"\" style=\"margin-bottom: 0px; line-height: 22px; color: rgb(93, 105, 116); font-size: 1rem;\"></p><p style=\"margin-bottom: 1rem; line-height: 1.5rem;\">A copy of 